INSERT INTO public.evaluation_periods (id, organization_id, name, is_current, created_at, updated_at) VALUES ('b4923a77-15a9-4af9-a655-728874ba9753', '11111111-1111-1111-1111-111111111111', '2026年12月', false, '2026-07-13 07:45:20.886462+00', '2026-07-13 07:45:20.886462+00');
INSERT INTO public.evaluation_periods (id, organization_id, name, is_current, created_at, updated_at) VALUES ('aeac0e71-f037-4978-812e-2461811492b9', '11111111-1111-1111-1111-111111111111', '2027年3月', true, '2026-07-13 09:17:33.658697+00', '2026-07-13 09:17:33.658697+00');
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('e1e1e1e1-e1e1-e1e1-e1e1-e1e1e1e1e1e1', '11111111-1111-1111-1111-111111111111', 'f1f1f1f1-f1f1-f1f1-f1f1-f1f1f1f1f1f1', 'bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作：自分から後輩へ声をかけて良い関係を築く。バリスタ：毎日カフェラテの練習をする。 キャッシャー：お客さまへ、天気や注文されたものなど些細なことでもいいので声をかける。', '総合的にみて仕事はある程度できます。仕事がとても丁寧で好感がもてます。次のステップとして後輩を指導してお店の中心になっていきましょう。', 'キャッシャーでは自らお客様へ商品を進めることができる。バリスタでは忙しい時間帯でもカフェラテをきれいに作成できるようになっている。後輩を指導できている。', '2026-06-24 08:25:24.199888+00', '2026-06-24 08:25:24.199888+00');
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('e2e2e2e2-e2e2-e2e2-e2e2-e2e2e2e2e2e2', '11111111-1111-1111-1111-111111111111', 'f1f1f1f1-f1f1-f1f1-f1f1-f1f1f1f1f1f1', 'cccccccc-cccc-cccc-cccc-cccccccccccc', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作：腸内検査、シフト提出期限を守りましょう。信頼につながります。バリスタ：マニュアルを暗記できていないところがあるので、勤務前にしっかりと確認しましょう。キャッシャー：緊張で声が小さくなる場面があるので、徐々に声のボリュームを上げましょう。', '基本的な作業は出来るようになりました。そしてドリンク作成技術が高いです。真面目に仕事を取り組んでいてとても好感が持てます。先輩の後ろ姿を参考にして、マニュアルに無い仕事の動きなど、応用的な力をつけていきましょう。', 'キャッシャーでは堂々とした対応でお客様へ安心感を届けることができる。バリスタでは商品の作成ミスを無くし、正確に作業ができるようになっている。', '2026-06-24 08:25:24.199888+00', '2026-06-24 08:25:24.199888+00');
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('117ff170-0d39-4a0e-b2c7-d28e3bb74e18', '11111111-1111-1111-1111-111111111111', 'f2f2f2f2-f2f2-f2f2-f2f2-f2f2f2f2f2f2', 'bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作: 前回と同じくもう少し後輩への声掛けを積極的にできればなおよし。なので大学生活のことなど些細なことから声をかけいい雰囲気作りを心がけよう！
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('8dd34ac5-cbbb-47f8-864e-9d0a2d885475', '11111111-1111-1111-1111-111111111111', 'f2f2f2f2-f2f2-f2f2-f2f2-f2f2f2f2f2f2', 'cccccccc-cccc-cccc-cccc-cccccccccccc', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作：シフトや腸内検査の提出期限が守れるようになり、責任ある行動ができるようになったのは素晴らしい！今後はクレーム対応など高度なことに挑戦しよう。
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('fae5feb9-dd94-423e-92fa-5396ff8d1cde', '11111111-1111-1111-1111-111111111111', 'b4923a77-15a9-4af9-a655-728874ba9753', 'bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作:コーヒーのテイスティングをして味わいの違いなどをお客様に伝えられるようになりましょう。そして前回より後輩に対して声かけができています。継続していきましょう。
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('159b82ab-3a0f-475d-8a98-0737d52fef25', '11111111-1111-1111-1111-111111111111', 'b4923a77-15a9-4af9-a655-728874ba9753', 'cccccccc-cccc-cccc-cccc-cccccccccccc', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作:後輩や周りの人への配慮などよく気がつくようになっています。今後は電話対応や普段の業務のイレギュラー対応をできるようしていきましょう。そのためにまずは周囲の異変に気づけるように些細なことでもいいのでメモするクセをつけましょう。
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('d4c7882e-2775-4a91-8796-6e37a2672da0', '11111111-1111-1111-1111-111111111111', 'aeac0e71-f037-4978-812e-2461811492b9', 'bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作：新人さんへ声掛けできています。小さなクレームは解決できるようになりました。次のステップとしてイレギュラーな対応ができるようになりましょう。そのために社員用のマニュアルを少しづつインプットしていきましょう。
INSERT INTO public.evaluations (id, organization_id, evaluation_period_id, staff_id, evaluator_id, evaluation_date, status, action_plan, total_comment, future_vision, created_at, updated_at) VALUES ('3056f082-ab17-47c6-8b5a-743b4e046832', '11111111-1111-1111-1111-111111111111', 'aeac0e71-f037-4978-812e-2461811492b9', 'cccccccc-cccc-cccc-cccc-cccccccccccc', 'aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', '2026-07-13', 'completed', '基本動作：電話対応やイレギュラー対応を冷静にこなしていて頼もしいです。そして３ヶ月まえに伝えた、些細なことをメモにとることを継続できています。その調子で経験を増やしていきましょう。
INSERT INTO public.evaluation_sections (id, evaluation_id, organization_id, section_type, good_points, improvement_points, skill_score, skill_max, hospitality_score, hospitality_max, cleanliness_score, cleanliness_max, created_at, updated_at) VALUES ('a1a1a1a1-a1a1-a1a1-a1a1-a1a1a1a1a1a1', 'e1e1e1e1-e1e1-e1e1-e1e1-e1e1e1e1e1e1', '11111111-1111-1111-1111-111111111111', 'basic', '{返事が明るくて良い,遅刻なし,姿勢が良い,仲間に対して優しい}', '{遅刻時にLINEでは無くて電話で連絡するように}', 28, 32, 13, 20, 23, 24, '2026-06-24 08:25:24.199888+00', '2026-06-24 08:25:24.199888+00');
